//! `parity_boogu_c6` — Boogu-Image full-DiT (C1-C6) numeric parity gate.
//!
//! DECISIVE correctness gate for the whole pure-Rust Boogu DiT
//! (`inference_flame::models::boogu::BooguDiT`). Loads the SAME fixed inputs the
//! Python reference used (`src/models/boogu/parity/c6_inputs.safetensors`,
//! generated by `gen_refs_c6.py` from seed 42 — byte-identical across both
//! sides, NOT regenerated by Rust randn), loads the real transformer weights via
//! `BooguDiT::load`, runs `forward`, and compares the final velocity against the
//! Python oracle's `parity/refs/c6_velocity.safetensors`.
//!
//! BAR: final velocity cosine similarity >= 0.999 vs the oracle. The verified
//! Mojo port hit 0.9998966 on the same model + probe shape.
//!
//! The Python ref generator and this Rust runner must run SEQUENTIALLY (each
//! needs ~20 GB; never concurrently).
//!
//! USAGE:
//! ```text
//! cd /home/alex/EriDiffusion/inference-flame
//! /home/alex/serenityflow-v2/.venv/bin/python src/models/boogu/parity/gen_refs_c6.py
//! cargo run --release --bin parity_boogu_c6
//! ```

use std::path::{Path, PathBuf};
use std::sync::Arc;

use anyhow::{anyhow, Context, Result};
use cudarc::driver::CudaDevice;

use flame_core::serialization::load_file;
use flame_core::{DType, Tensor};
use inference_flame::models::boogu::{BooguConfig, BooguDiT};

const REPO: &str = "/home/alex/Boogu-Image/models/Boogu-Image-0.1-Base";

fn parity_dir() -> PathBuf {
    PathBuf::from("/home/alex/EriDiffusion/inference-flame/src/models/boogu/parity")
}

/// Load a single-tensor safetensors file (Python writer uses key `"tensor"`).
fn load_single(path: &Path, device: &Arc<CudaDevice>) -> Result<Tensor> {
    let map = load_file(path, device).map_err(|e| anyhow!("load {}: {e}", path.display()))?;
    map.get("tensor")
        .cloned()
        .with_context(|| format!("missing 'tensor' key in {}", path.display()))
}

/// Cosine similarity + max-abs-diff (computed in F64 for stability).
fn cosine_stats(ours: &[f32], reference: &[f32]) -> (f64, f32) {
    assert_eq!(ours.len(), reference.len());
    let mut dot = 0.0f64;
    let mut nn1 = 0.0f64;
    let mut nn2 = 0.0f64;
    let mut max_abs = 0.0f32;
    for (a32, b32) in ours.iter().zip(reference.iter()) {
        let a = *a32 as f64;
        let b = *b32 as f64;
        dot += a * b;
        nn1 += a * a;
        nn2 += b * b;
        let d = (a32 - b32).abs();
        if d > max_abs {
            max_abs = d;
        }
    }
    let cos = if nn1 > 0.0 && nn2 > 0.0 {
        dot / (nn1.sqrt() * nn2.sqrt())
    } else {
        0.0
    };
    (cos, max_abs)
}

/// Compare an optional Rust capture against a ref file if present, printing a row.
fn compare_row(
    name: &str,
    ours: Option<&Tensor>,
    refs_dir: &Path,
    device: &Arc<CudaDevice>,
) -> Result<()> {
    let ref_path = refs_dir.join(format!("{name}.safetensors"));
    if !ref_path.is_file() {
        return Ok(());
    }
    let our_t = match ours {
        Some(t) => t,
        None => return Ok(()), // no Rust capture for this stage
    };
    let ref_t = load_single(&ref_path, device)?;
    let our_f32 = our_t.to_dtype(DType::F32)?.to_vec_f32()?;
    let ref_f32 = ref_t.to_dtype(DType::F32)?.to_vec_f32()?;
    if our_f32.len() != ref_f32.len() {
        println!(
            "{:>26} | {:>10} | {:>10} | SHAPE MISMATCH our={:?} ref={:?}",
            name,
            "-",
            "-",
            our_t.shape().dims(),
            ref_t.shape().dims()
        );
        return Ok(());
    }
    let (cos, max_abs) = cosine_stats(&our_f32, &ref_f32);
    println!(
        "{:>26} | {:>10.7} | {:>10.4e} | {:?}",
        name,
        cos,
        max_abs,
        our_t.shape().dims()
    );
    Ok(())
}

fn main() -> Result<()> {
    let device = CudaDevice::new(0).context("cuda device 0")?;
    let pdir = parity_dir();
    let refs = pdir.join("refs");
    let inputs_path = pdir.join("c6_inputs.safetensors");
    if !inputs_path.is_file() {
        return Err(anyhow!(
            "missing {} — run gen_refs_c6.py first",
            inputs_path.display()
        ));
    }

    // --- Load the SAME fixed inputs the Python ref used (byte-identical). ---
    let in_map = load_file(&inputs_path, &device)
        .map_err(|e| anyhow!("load inputs {}: {e}", inputs_path.display()))?;
    let latent = in_map
        .get("latent")
        .cloned()
        .context("inputs missing 'latent'")?;
    let instruction_f32 = in_map
        .get("instruction")
        .cloned()
        .context("inputs missing 'instruction'")?;
    let timestep_t = in_map
        .get("timestep")
        .cloned()
        .context("inputs missing 'timestep'")?;
    let timestep: Vec<f32> = timestep_t.to_dtype(DType::F32)?.to_vec_f32()?;
    // The DiT caption path runs in BF16; cast instruction F32 -> BF16 (the
    // forward casts the latent internally, raw timestep passed as-is).
    let instruction = instruction_f32.to_dtype(DType::BF16)?;

    println!(
        "[parity_boogu_c6] inputs: latent={:?} instruction={:?} timestep={:?}",
        latent.shape().dims(),
        instruction.shape().dims(),
        timestep
    );

    // --- Load real transformer weights + build the resident DiT. ---
    let t0 = std::time::Instant::now();
    let weights = inference_flame::models::boogu::loader::load_component(
        Path::new(REPO),
        "transformer",
        &device,
    )
    .map_err(|e| anyhow!("load transformer weights: {e}"))?;
    println!(
        "[parity_boogu_c6] loaded {} transformer tensors in {:.1}s",
        weights.len(),
        t0.elapsed().as_secs_f64()
    );

    let dit = BooguDiT::load(weights, BooguConfig::default(), device.clone())
        .map_err(|e| anyhow!("BooguDiT::load: {e}"))?;

    // --- Run the full DiT forward. ---
    let t1 = std::time::Instant::now();
    let velocity = dit
        .forward(&latent, &timestep, &instruction)
        .map_err(|e| anyhow!("BooguDiT::forward: {e}"))?;
    let fwd_s = t1.elapsed().as_secs_f64();

    // Peak GPU memory (resident DiT + forward) at this probe shape.
    let (free_b, total_b) = cudarc::driver::result::mem_get_info().unwrap_or((0, 0));
    let used_gb = (total_b.saturating_sub(free_b)) as f64 / 1e9;

    println!(
        "[parity_boogu_c6] forward done in {:.2}s, velocity={:?} dtype={:?}",
        fwd_s,
        velocity.shape().dims(),
        velocity.dtype()
    );
    println!("[parity_boogu_c6] GPU used (after forward): {:.2} GB", used_gb);

    // --- Parity table. ---
    println!("\n{:>26} | {:>10} | {:>10} | shape", "capture", "cos", "max_abs");
    println!("{}", "-".repeat(72));
    // Stage intermediates are NOT captured Rust-side (the forward composes the
    // C1-C5 pieces with no public capture hook; adding one was deemed not
    // straightforward enough to justify for this pass — see report). If/when a
    // `forward_captured` exists, pass the captures here. For now only the final
    // velocity is the gate; refs/*.safetensors for stages remain available for a
    // follow-up bisection bin.
    compare_row("c6_velocity", Some(&velocity), &refs, &device)?;

    // --- Verdict. ---
    let ref_vel = load_single(&refs.join("c6_velocity.safetensors"), &device)?;
    let our_f32 = velocity.to_dtype(DType::F32)?.to_vec_f32()?;
    let ref_f32 = ref_vel.to_dtype(DType::F32)?.to_vec_f32()?;
    if our_f32.len() != ref_f32.len() {
        return Err(anyhow!(
            "final velocity shape mismatch: our {} vs ref {} elems",
            our_f32.len(),
            ref_f32.len()
        ));
    }
    let (cos, max_abs) = cosine_stats(&our_f32, &ref_f32);
    let our_std = {
        let n = our_f32.len() as f64;
        let mean = our_f32.iter().map(|&v| v as f64).sum::<f64>() / n;
        (our_f32.iter().map(|&v| (v as f64 - mean).powi(2)).sum::<f64>() / n).sqrt()
    };
    let ref_std = {
        let n = ref_f32.len() as f64;
        let mean = ref_f32.iter().map(|&v| v as f64).sum::<f64>() / n;
        (ref_f32.iter().map(|&v| (v as f64 - mean).powi(2)).sum::<f64>() / n).sqrt()
    };
    println!(
        "\nfinal velocity: cos={:.7} max_abs={:.4e} our_std={:.4} ref_std={:.4}",
        cos, max_abs, our_std, ref_std
    );
    if cos >= 0.999 {
        println!("\nVERDICT: PASS (final DiT velocity cos {:.7} >= 0.999)", cos);
        Ok(())
    } else {
        println!(
            "\nVERDICT: FAIL (final DiT velocity cos {:.7} < 0.999, max_abs {:.4e})",
            cos, max_abs
        );
        std::process::exit(1);
    }
}
